Here is the program.

```
#include <string>
#include <iostream>
#include <fstream>

using namespace std;

// ----------------------------------------------------------------------------------------

int main(int argc, char** argv) try
{
  std::string line;
  ifstream myfile ("pics.txt");
  if (myfile.is_open())
  {
    while ( getline (myfile,line))
    {
        cout << line << '\n';
    }
    myfile.close();
  }

  else cout << "Unable to open file";

}
catch (std::exception& e)
{
    cout << e.what() << endl;
}
```

It compiles correctly with `i=../crop_imgs_test && g++ -std=c++11 $i.cpp -o $i` but when I added it in the CMakeLists.txt, dlib was compiled successfully but my example was not.

```
CMakeFiles/crop_imgs_test.dir/crop_imgs_test.cpp.o: In function `main':
crop_imgs_test.cpp:(.text.startup+0x5f): undefined reference to `std::basic_istream<char, std::char_traits<char> >& std::getline<char, std::char_traits<char>, std::allocator<char> >(std::basic_istream<char, std::char_traits<char> >&, std::__cxx11::basic_string<char, std::char_traits<char>, std::allocator<char> >&, char)'
collect2: error: ld returned 1 exit status
