Schema.loads fails with TypeError:

```py
from marshmallow import Schema, fields, post_load, ValidationError

class User:
    def __init__(self, name=None, email=None):
        self.name = name
        self.email = email
        
    def __repr__(self):
        return f'<User(name={self.name!r})>'

class UserSchema(Schema):
    name = fields.Str()
    email = fields.Email()
    created = fields.DateTime()

    @post_load
    def load(self, data):
        return User(**data)

if __name__ == '__main__':
    json = '{"name":"should_load", "email" : "test@test.com"}'
    schema = UserSchema()
    user = schema.loads(json)
    print(user)
```

